
import { ref, Ref, onMounted, reactive } from 'vue';
import headers from './components/header.vue';
import { getUrlParam, parseTime, getUrlParamNew } from '@/utils/index';
import { ImagePreview } from 'vant';
import api from './service/api';

export default {
  name: 'teachDetail',
  components: {
    headers,
  },
  setup() {

    const title = ref('')
    let list: Ref<any[]> = ref([])
    // 接口调用demo
    const getConfig = async () => {
      const params = {
        tal_id: getUrlParam('tal_id') || '',
        date: getUrlParam('date') || '',
        source: getUrlParam('source') || '',
        label: decodeURIComponent(getUrlParamNew('label') || ''),
        xpad_type: getUrlParamNew('xpad_type') || ''
      }

      const res: any = await api.getTeachAssistantList(params)


      if (res.data.errcode === 0 && Object.prototype.toString.call(res.data.data) === '[object Object]') {
        list.value = res.data.data.knowledge
        title.value = res.data.data.title
      }
    }
    const formatTime = (item: any) => {
      const time = parseTime(item, '{h}:{i}')
      return time
    }
    const previewPicture = (item: any) => {
      ImagePreview({ images: [item.img_url], showIndex: false, overlayStyle: { background: '#000' } });
    }

    onMounted(() => {
      getConfig()
    })


    return {
      headers,
      previewPicture,
      list,
      formatTime,
      title
    }
  }
}
